import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),r={name:"guide/introduction.md"};function o(i,t,l,d,c,p){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>GeniusHRM is a fully open-source, enterprise-grade Human Resource Management System built for modern teams. It delivers a comprehensive suite of HR tools in a clean, modular architecture — enabling organisations of any size to manage their workforce with confidence.</p><p>Whether you are a small business with 10 employees or an enterprise managing hundreds, GeniusHRM provides the tools to automate HR operations, enforce compliance, and gain data-driven insights into your workforce.</p><hr><h2 id="what-is-geniushrm" tabindex="-1">What is GeniusHRM? <a class="header-anchor" href="#what-is-geniushrm" aria-label="Permalink to &quot;What is GeniusHRM?&quot;">​</a></h2><p>GeniusHRM is a <strong>Laravel 13 + React 18 + TypeScript</strong> web application that covers the full employee lifecycle — from recruitment and onboarding through performance management, payroll, and offboarding. It is built with a modular architecture using <code>nwidart/laravel-modules</code>, meaning each functional area (Employees, Payroll, Attendance, etc.) is an independent Laravel module that can be enabled, disabled, or extended without touching core code.</p><p>The system ships with <strong>demo data seeders</strong>, so you can evaluate every feature immediately after installation without manual data entry.</p><hr><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Complete Employee Lifecycle</strong> — Hire, manage, and offboard employees with full audit trails</li><li><strong>Modular Architecture</strong> — 12 independent modules built on <code>nwidart/laravel-modules</code></li><li><strong>Role-Based Access Control</strong> — 6 built-in roles with granular permission matrices</li><li><strong>Payroll Engine</strong> — Multi-component salary structures with 2-pass tax calculation</li><li><strong>Attendance &amp; Shift Management</strong> — Manual and API-driven clock-in/out</li><li><strong>Leave Approval Workflows</strong> — Multi-step leave request and approval process</li><li><strong>Recruitment (ATS)</strong> — Job postings, application pipeline, interview scheduling</li><li><strong>Performance Appraisals</strong> — Configurable cycles with self-assessment and manager scoring</li><li><strong>Training Management</strong> — Courses, sessions, enrollments, completion tracking</li><li><strong>Documents &amp; Compliance</strong> — Company and personal document management with acknowledgements</li><li><strong>Analytics Dashboards</strong> — KPI cards and charts for every module</li><li><strong>RESTful API</strong> — Full JSON API with Bearer token authentication</li><li><strong>Audit Log</strong> — Every action logged with user, IP, and timestamp</li><li><strong>Multi-language Ready</strong> — Laravel localisation support built in</li></ul><hr><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th></tr></thead><tbody><tr><td>Backend Framework</td><td>Laravel 13</td></tr><tr><td>Frontend Framework</td><td>React 18</td></tr><tr><td>Language</td><td>TypeScript</td></tr><tr><td>Bridge</td><td>Inertia.js</td></tr><tr><td>Styling</td><td>Tailwind CSS</td></tr><tr><td>Component Library</td><td>shadcn/ui</td></tr><tr><td>Database</td><td>MySQL 8.0+</td></tr><tr><td>Module System</td><td>nwidart/laravel-modules</td></tr><tr><td>Build Tool</td><td>Vite</td></tr><tr><td>Authentication</td><td>Laravel Sanctum</td></tr><tr><td>PDF Generation</td><td>DomPDF / Barryvdh</td></tr><tr><td>Queue</td><td>Laravel Queue (database driver)</td></tr></tbody></table><hr><h2 id="module-overview" tabindex="-1">Module Overview <a class="header-anchor" href="#module-overview" aria-label="Permalink to &quot;Module Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Description</th></tr></thead><tbody><tr><td><strong>Employees</strong></td><td>Full employee CRUD, profile management, employment history, document attachment</td></tr><tr><td><strong>Organization</strong></td><td>Departments, positions, reporting lines, org chart</td></tr><tr><td><strong>Attendance</strong></td><td>Clock-in/out, shift scheduling, attendance statuses, reports</td></tr><tr><td><strong>Leave</strong></td><td>Leave types, allowances, request submission, approval workflow, calendar</td></tr><tr><td><strong>Payroll</strong></td><td>Salary components, structures, payroll runs, payslips, PDF download</td></tr><tr><td><strong>Recruitment</strong></td><td>Job postings, candidate pipeline, interviews, offer management</td></tr><tr><td><strong>Performance</strong></td><td>Appraisal cycles, self/manager scores, finalised ratings, reports</td></tr><tr><td><strong>Training</strong></td><td>Courses, sessions, enrollments, completion and scoring</td></tr><tr><td><strong>Documents</strong></td><td>Company and personal documents, acknowledgement tracking</td></tr><tr><td><strong>Reports</strong></td><td>Unified analytics dashboard covering all modules</td></tr><tr><td><strong>Settings</strong></td><td>SMTP, SMS, branding, financial year, currency, timezone</td></tr><tr><td><strong>Users &amp; RBAC</strong></td><td>User accounts, roles, granular permissions, audit log</td></tr></tbody></table><hr><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>GeniusHRM follows a <strong>modular monolith</strong> pattern. All feature code lives inside <code>Modules/</code> — each module contains its own:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Modules/</span></span>
<span class="line"><span>  Employees/</span></span>
<span class="line"><span>    Config/</span></span>
<span class="line"><span>    Database/</span></span>
<span class="line"><span>      Migrations/</span></span>
<span class="line"><span>      Seeders/</span></span>
<span class="line"><span>    Http/</span></span>
<span class="line"><span>      Controllers/</span></span>
<span class="line"><span>      Requests/</span></span>
<span class="line"><span>      Resources/</span></span>
<span class="line"><span>    Models/</span></span>
<span class="line"><span>    Providers/</span></span>
<span class="line"><span>    Routes/</span></span>
<span class="line"><span>    resources/</span></span>
<span class="line"><span>      js/</span></span>
<span class="line"><span>        Pages/</span></span>
<span class="line"><span>        Components/</span></span></code></pre></div><p>The React frontend communicates with Laravel via <strong>Inertia.js</strong> — no separate API server is needed for the UI. A dedicated RESTful JSON API layer (<code>/api/v1/</code>) is available for mobile apps or third-party integrations, secured via <strong>Laravel Sanctum</strong> Bearer tokens.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser (React + TypeScript)</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>   Inertia.js</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>Laravel 13 (Modules via nwidart)</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>   MySQL 8</span></span></code></pre></div><hr><h2 id="who-is-geniushrm-for" tabindex="-1">Who Is GeniusHRM For? <a class="header-anchor" href="#who-is-geniushrm-for" aria-label="Permalink to &quot;Who Is GeniusHRM For?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>HR Teams</strong></td><td>Replace spreadsheets with a structured, auditable system</td></tr><tr><td><strong>SMEs (10–500 employees)</strong></td><td>Full HR suite without enterprise licensing costs</td></tr><tr><td><strong>Enterprises</strong></td><td>Self-hosted, customisable, extensible via Laravel modules</td></tr><tr><td><strong>Developers</strong></td><td>Clean codebase as a starting point for custom HR solutions</td></tr><tr><td><strong>Consultancies</strong></td><td>White-label and deploy for clients</td></tr></tbody></table><hr><h2 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h2><ul><li><a href="/guide/installation.html">Installation Guide</a> — Get up and running in minutes</li><li><a href="/guide/configuration.html">Configuration</a> — Set up email, SMS, branding</li><li><a href="/guide/demo-accounts.html">Demo Accounts</a> — Try every role out of the box</li><li><a href="/modules/employees.html">Module Docs</a> — Deep-dive into each feature area</li><li><a href="/api/overview.html">API Reference</a> — Integrate with your existing tools</li></ul>`,28)])])}const h=e(r,[["render",o]]);export{g as __pageData,h as default};
